from __future__ import annotations

from dataclasses import dataclass, field, replace
from datetime import datetime, timezone
from enum import Enum
from heapq import heappop, heappush
from types import TracebackType
from typing import Generic, Iterable, Iterator, TypeAlias, TypeVar
from uuid import UUID, uuid4


T = TypeVar("T")
TaskId: TypeAlias = UUID | str


class PriorityTaskQueueError(Exception):
    """Base exception for PriorityTaskQueue errors."""


class EmptyQueueError(PriorityTaskQueueError):
    """Raised when reading from an empty queue."""


class TaskNotFoundError(PriorityTaskQueueError):
    """Raised when a task ID does not refer to an active task."""


class TaskStatus(str, Enum):
    """Lifecycle state for a task."""

    PENDING = "pending"
    DEQUEUED = "dequeued"
    CANCELLED = "cancelled"


@dataclass(frozen=True, slots=True, kw_only=True)
class Task(Generic[T]):
    """A task managed by PriorityTaskQueue."""

    id: UUID = field(default_factory=uuid4)
    payload: T
    priority: int
    created_at: datetime = field(default_factory=lambda: datetime.now(timezone.utc))
    status: TaskStatus = TaskStatus.PENDING


@dataclass(order=True, slots=True)
class _HeapEntry:
    """Internal heap entry ordered by priority descending, then FIFO sequence."""

    heap_priority: int
    sequence: int
    task_id: UUID = field(compare=False)
    version: int = field(compare=False)


class PriorityTaskQueue(Generic[T]):
    """A FIFO-stable priority queue for typed task payloads.

    Higher integer priority values are returned first. Tasks with the same
    priority are returned in insertion order. Updating a task's priority keeps
    its original FIFO position among tasks at the resulting priority.
    """

    def __init__(self, tasks: Iterable[tuple[T, int]] | None = None) -> None:
        """Create an empty queue, optionally seeded with payload/priority pairs."""
        self._heap: list[_HeapEntry] = []
        self._tasks: dict[UUID, Task[T]] = {}
        self._versions: dict[UUID, int] = {}
        self._sequences: dict[UUID, int] = {}
        self._next_sequence = 0

        if tasks is not None:
            for payload, priority in tasks:
                self.add_task(payload, priority)

    @property
    def size(self) -> int:
        """Return the number of active tasks in the queue."""
        return len(self)

    def add_task(self, payload: T, priority: int) -> Task[T]:
        """Add a task and return the created Task object."""
        self._validate_priority(priority)

        task = Task(payload=payload, priority=priority)
        sequence = self._next_sequence
        self._next_sequence += 1

        self._tasks[task.id] = task
        self._versions[task.id] = 0
        self._sequences[task.id] = sequence
        heappush(self._heap, _HeapEntry(-priority, sequence, task.id, 0))
        return task

    def get_next_task(self) -> Task[T]:
        """Remove and return the next highest-priority task.

        Raises:
            EmptyQueueError: If the queue has no active tasks.
        """
        self._discard_stale_entries()

        if not self._heap:
            raise EmptyQueueError("Cannot get a task from an empty queue.")

        entry = heappop(self._heap)
        task = self._tasks.pop(entry.task_id)
        self._versions.pop(entry.task_id, None)
        self._sequences.pop(entry.task_id, None)
        return replace(task, status=TaskStatus.DEQUEUED)

    def peek_next_task(self) -> Task[T]:
        """Return the next highest-priority task without removing it.

        Raises:
            EmptyQueueError: If the queue has no active tasks.
        """
        self._discard_stale_entries()

        if not self._heap:
            raise EmptyQueueError("Cannot peek at an empty queue.")

        return self._tasks[self._heap[0].task_id]

    def cancel_task(self, task_id: TaskId) -> Task[T]:
        """Remove an active task by ID and return it marked as cancelled.

        Raises:
            TaskNotFoundError: If no active task exists for the given ID.
        """
        normalized_id = self._normalize_task_id(task_id)
        task = self._tasks.pop(normalized_id, None)

        if task is None:
            raise TaskNotFoundError(f"Task {task_id!s} was not found.")

        self._versions.pop(normalized_id, None)
        self._sequences.pop(normalized_id, None)
        return replace(task, status=TaskStatus.CANCELLED)

    def remove_task(self, task_id: TaskId) -> Task[T]:
        """Alias for cancel_task, useful when removal terminology fits better."""
        return self.cancel_task(task_id)

    def update_task_priority(self, task_id: TaskId, priority: int) -> Task[T]:
        """Update an active task's priority and return the updated Task.

        Raises:
            TaskNotFoundError: If no active task exists for the given ID.
            TypeError: If priority is not an integer.
        """
        self._validate_priority(priority)

        normalized_id = self._normalize_task_id(task_id)
        task = self._tasks.get(normalized_id)

        if task is None:
            raise TaskNotFoundError(f"Task {task_id!s} was not found.")

        if task.priority == priority:
            return task

        version = self._versions[normalized_id] + 1
        updated = replace(task, priority=priority)

        self._tasks[normalized_id] = updated
        self._versions[normalized_id] = version
        heappush(
            self._heap,
            _HeapEntry(-priority, self._sequences[normalized_id], normalized_id, version),
        )
        return updated

    def get_task(self, task_id: TaskId) -> Task[T]:
        """Return an active task by ID without removing it.

        Raises:
            TaskNotFoundError: If no active task exists for the given ID.
        """
        normalized_id = self._normalize_task_id(task_id)
        task = self._tasks.get(normalized_id)

        if task is None:
            raise TaskNotFoundError(f"Task {task_id!s} was not found.")

        return task

    def tasks_with_priority(self, priority: int) -> list[Task[T]]:
        """Return active tasks with the given priority in FIFO order."""
        self._validate_priority(priority)
        return [
            task
            for task in self.list_tasks()
            if task.priority == priority
        ]

    def list_tasks(self) -> list[Task[T]]:
        """Return all active tasks in dequeue order without removing them."""
        return sorted(
            self._tasks.values(),
            key=lambda task: (-task.priority, self._sequences[task.id]),
        )

    def clear(self) -> None:
        """Remove all active tasks from the queue."""
        self._heap.clear()
        self._tasks.clear()
        self._versions.clear()
        self._sequences.clear()
        self._next_sequence = 0

    def is_empty(self) -> bool:
        """Return True when the queue has no active tasks."""
        return len(self) == 0

    def __len__(self) -> int:
        """Return the number of active tasks."""
        return len(self._tasks)

    def __bool__(self) -> bool:
        """Return True when the queue contains at least one active task."""
        return not self.is_empty()

    def __iter__(self) -> Iterator[Task[T]]:
        """Iterate over active tasks in dequeue order without removing them."""
        return iter(self.list_tasks())

    def __enter__(self) -> PriorityTaskQueue[T]:
        """Enter a context manager block and return this queue."""
        return self

    def __exit__(
        self,
        exc_type: type[BaseException] | None,
        exc: BaseException | None,
        traceback: TracebackType | None,
    ) -> bool:
        """Clear the queue on context exit and do not suppress exceptions."""
        self.clear()
        return False

    def __repr__(self) -> str:
        """Return a concise developer-facing representation of the queue."""
        priorities: dict[int, int] = {}
        for task in self._tasks.values():
            priorities[task.priority] = priorities.get(task.priority, 0) + 1

        priority_summary = ", ".join(
            f"{priority}: {count}"
            for priority, count in sorted(priorities.items(), reverse=True)
        )
        return (
            f"{type(self).__name__}(size={len(self)}, "
            f"priorities={{{priority_summary}}})"
        )

    def _discard_stale_entries(self) -> None:
        """Remove heap entries for cancelled, dequeued, or reprioritized tasks."""
        while self._heap:
            entry = self._heap[0]
            task = self._tasks.get(entry.task_id)
            version = self._versions.get(entry.task_id)

            if task is not None and version == entry.version:
                return

            heappop(self._heap)

    def _normalize_task_id(self, task_id: TaskId) -> UUID:
        """Convert a supported task ID value into a UUID."""
        if isinstance(task_id, UUID):
            return task_id

        try:
            return UUID(task_id)
        except ValueError as exc:
            raise TaskNotFoundError(f"Task {task_id!s} was not found.") from exc

    def _validate_priority(self, priority: int) -> None:
        """Validate that a priority value is an integer."""
        if isinstance(priority, bool) or not isinstance(priority, int):
            raise TypeError("priority must be an integer.")
